import{_ as a,o as t,c as o,ai as s}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Health Checks","description":"","frontmatter":{"summary":"How the macOS app reports gateway/Baileys health states","read_when":["Debugging mac app health indicators"],"title":"Health Checks"},"headers":[],"relativePath":"platforms/mac/health.md","filePath":"platforms/mac/health.md","lastUpdated":null}'),l={name:"platforms/mac/health.md"};function n(h,e,r,c,i,d){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="health-checks-on-macos" tabindex="-1"><a class="header-anchor" href="#health-checks-on-macos">#</a> Health Checks on macOS</h1><p>How to see whether the linked channel is healthy from the menu bar app.</p><h2 id="menu-bar" tabindex="-1"><a class="header-anchor" href="#menu-bar">#</a> Menu bar</h2><ul><li>Status dot now reflects Baileys health: <ul><li>Green: linked + socket opened recently.</li><li>Orange: connecting/retrying.</li><li>Red: logged out or probe failed.</li></ul></li><li>Secondary line reads &quot;linked · auth 12m&quot; or shows the failure reason.</li><li>&quot;Run Health Check&quot; menu item triggers an on-demand probe.</li></ul><h2 id="settings" tabindex="-1"><a class="header-anchor" href="#settings">#</a> Settings</h2><ul><li>General tab gains a Health card showing: linked auth age, session-store path/count, last check time, last error/status code, and buttons for Run Health Check / Reveal Logs.</li><li>Uses a cached snapshot so the UI loads instantly and falls back gracefully when offline.</li><li><strong>Channels tab</strong> surfaces channel status + controls for WhatsApp/Telegram (login QR, logout, probe, last disconnect/error).</li></ul><h2 id="how-the-probe-works" tabindex="-1"><a class="header-anchor" href="#how-the-probe-works">#</a> How the probe works</h2><ul><li>App runs <code>opensoul health --json</code> via <code>ShellExecutor</code> every ~60s and on demand. The probe loads creds and reports status without sending messages.</li><li>Cache the last good snapshot and the last error separately to avoid flicker; show the timestamp of each.</li></ul><h2 id="when-in-doubt" tabindex="-1"><a class="header-anchor" href="#when-in-doubt">#</a> When in doubt</h2><ul><li>You can still use the CLI flow in <a href="/docs/gateway/health">Gateway health</a> (<code>opensoul status</code>, <code>opensoul status --deep</code>, <code>opensoul health --json</code>) and tail <code>/tmp/opensoul/opensoul-*.log</code> for <code>web-heartbeat</code> / <code>web-reconnect</code>.</li></ul>',10)])])}const m=a(l,[["render",n]]);export{p as __pageData,m as default};
